import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { surfaceIsNamespaceRule } from "./surface-is-namespace.rule.js";

describe("surface-is-namespace rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, surfaceIsNamespaceRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_surface_is_namespace
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_01
    it("T016_01: @uiRoute namespace inside @component(Ui) — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.ReviewUi {
            @uiRoute(#{ path: "/reviews" })
            namespace Routes.ReviewList {
              op on_mount(): UiCommand;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_02
    it("T016_02: non-@uiRoute namespace — rule skips it", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {}
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_03
    it("T016_03: nested @uiRoute namespace inside another @uiRoute inside @component(Ui) — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Ui })
          namespace Components.ReviewUi {
            @uiRoute(#{ path: "/reviews" })
            namespace Routes.ReviewList {
              @uiRoute
              namespace FilterPanel {
                op on_apply(): UiCommand;
              }
              op on_mount(): UiCommand;
            }
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_05
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_surface_is_namespace:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.surface_is_namespace:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_sdk_operations_namespace:Products.A10nBlueprintEngine.Features.UiRouteAuthoring.surface_is_namespace:must
    it("T016_05: @uiRoute namespace inside a non-Ui @component — fires noUiComponent", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Agent })
          namespace Components.ReviewAgent {
            @uiRoute(#{ path: "/dashboard" })
            namespace Dashboard {
              op on_mount(): UiCommand;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/surface-is-namespace",
          message: /Dashboard/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T016.T016_06
    it("T016_06: @uiRoute namespace inside a Service @component — fires noUiComponent", async () => {
      await ruleTester
        .expect(`
          @component(#{ type: ComponentType.Service })
          namespace Components.ReviewApiService {
            @uiRoute(#{ path: "/admin" })
            namespace AdminPanel {
              op on_mount(): UiCommand;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/surface-is-namespace",
          message: /AdminPanel/,
        });
    });
  });
});
